/// The GC tables come from an anonymous mmap at startup instead of
/// zero-filled .data (GitHub issue #430), so binaries stay small even
/// though the tables hold tens of thousands of entries. A trivial
/// program's executable must stay well under the ~870KB the embedded
/// tables used to cost.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn native_binaries_do_not_embed_gc_tables() {
    let unique = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_binary_size_{unique}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_binary_size_{unique}.bin"));
    fs::write(&source_path, "println(\"hello\")\n").expect("temp source file should write");

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            output_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(build_output.status.success());
    let size = fs::metadata(&output_path)
        .expect("output should exist")
        .len();
    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);
    assert!(run_output.status.success());
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), "hello\n");
    assert!(
        size < 200_000,
        "trivial binary should not embed GC tables, got {size} bytes"
    );
}

/// Annotated String parameters/returns travel as GC heap pointers
/// (GitHub issue #424): every recursion frame owns its own string, so
/// recursive functions can build fresh strings per frame, >64KB
/// strings cross call boundaries, and `length` keeps character (not
/// byte) semantics on heap strings. The deep-churn case exercises the
/// caller pin/unpin balance and the shadow-stack/mark-worklist sizing
/// under collections.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn builds_native_executable_for_heap_string_parameters() {
    let unique = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_heap_string_abi_{unique}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_heap_string_abi_{unique}.bin"));
    let big = format!("{}TAIL", "y".repeat(69996));
    fs::write(
        &source_path,
        format!(
            "def describe(s: String, n: Int): String = if (n <= 0) s else describe(s + \"x\", n - 1)\n\
             def ident(s: String): String = s\n\
             def churn(s: String, n: Int): Int = if (n <= 0) length(s) else churn(s + \"ab\", n - 1)\n\
             def lastFour(s: String): String = substring(s, length(s) - 4, length(s))\n\
             def pick(s: String, i: Int): String = s.at(i)\n\
             println(describe(\"r\", 4))\n\
             println(length(describe(\"あいう\", 2)))\n\
             println(length(ident(\"{big}\")))\n\
             println(lastFour(ident(\"{big}\")))\n\
             println(pick(ident(\"{big}\"), 69997))\n\
             println(churn(\"\", 2000))\n"
        ),
    )
    .expect("temp source file should write");
    let expected = "rxxxx\n5\n70000\nTAIL\nA\n4000\n";

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            output_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "heap string ABI should compile\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);
    assert!(
        run_output.status.success(),
        "heap string ABI binary should run\nstderr:\n{}",
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), expected);
}

