#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn builds_native_executable_for_gc_reclaims_dead_allocations() {
    let unique = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("time should be monotonic")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic-native-gc-stress-{unique}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic-native-gc-stress-{unique}"));
    // Each loop iteration constructs an enum with a String payload; the
    // payload is normalized into a real GC heap allocation (see
    // `EnumFieldRepr::StringField` desugaring) and the enum value itself
    // is unreachable once the loop moves on, so 50k iterations force
    // several GC cycles that must reclaim dead allocations for every
    // subsequent iteration to keep succeeding.
    fs::write(
        &source_path,
        r#"enum Wrap { case S(v: String) }
mutable count = 0
mutable i = 0
while (i < 50000) {
  S("heap-string-data-for-gc-pressure")
  count = count + 1
  i = i + 1
}
println(count)
"#,
    )
    .expect("source should write");

    let build = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_string_lossy().as_ref(),
            "-o",
            output_path.to_string_lossy().as_ref(),
        ])
        .output()
        .expect("klassic build should run");

    assert!(
        build.status.success(),
        "gc stress build failed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&build.stdout),
        String::from_utf8_lossy(&build.stderr)
    );

    let run = Command::new(&output_path)
        .output()
        .expect("generated executable should run");

    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);

    assert!(run.status.success());
    assert_eq!(String::from_utf8_lossy(&run.stdout), "50000\n");
    assert!(run.stderr.is_empty());
}

#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn builds_native_executable_for_gc_string_to_string_bridge() {
    let unique = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("time should be monotonic")
        .as_nanos();
    let source_path =
        std::env::temp_dir().join(format!("klassic-native-gc-str-tostring-{unique}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic-native-gc-str-tostring-{unique}"));
    // `h` round-trips through an enum's String payload, which normalizes
    // into a real GC heap string (see `EnumFieldRepr::StringField`
    // desugaring) -- the same underlying representation the removed
    // `__gc_string` builtin used to expose directly.
    fs::write(
        &source_path,
        r#"enum Wrap { case S(v: String) }
def heap(s: String): String = S(s) match { case S(v) => v }
val h = heap("heap")
val s = toString(h)
val method = h.toString()
println(s)
println(method)
println(length(s))
val shouted = toString(h + heap("!"))
println(shouted)
assertResult("heap")(s)
assertResult("heap")(method)
assertResult("heap!")(shouted)
"#,
    )
    .expect("source should write");

    let build = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_string_lossy().as_ref(),
            "-o",
            output_path.to_string_lossy().as_ref(),
        ])
        .output()
        .expect("klassic build should run");

    assert!(
        build.status.success(),
        "gc string toString build failed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&build.stdout),
        String::from_utf8_lossy(&build.stderr)
    );

    let run = Command::new(&output_path)
        .output()
        .expect("generated executable should run");

    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);

    assert!(
        run.status.success(),
        "gc string toString run failed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&run.stdout),
        String::from_utf8_lossy(&run.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&run.stdout),
        "heap\nheap\n4\nheap!\n"
    );
    assert!(run.stderr.is_empty());
}

