/// PR 8: std.string / std.math / std.path are all reachable via the
/// embedded stdlib bundle from a single evaluator run.
#[test]
fn evaluator_imports_std_string_math_path_modules() {
    // `std.string` ships its members as extension methods on String —
    // they become callable via dot syntax (`"hi".nonEmpty()`)
    // automatically once the stdlib bundle is loaded, so the user
    // does not need to import them. `std.math` and `std.path`
    // continue to expose ordinary functions imported by member.
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "import std.math.{mod, clamp, sign}\n\
             import std.path.{basename, dirname, fileExtension, join}\n\
             println(\"hello\".nonEmpty())\n\
             println(\"a\\nb\\nc\".lines())\n\
             println(mod(10, 3))\n\
             println(clamp(15, 0, 10))\n\
             println(sign(-7))\n\
             println(basename(\"/usr/lib/foo.txt\"))\n\
             println(dirname(\"/usr/lib/foo.txt\"))\n\
             println(fileExtension(\"/usr/lib/foo.txt\"))\n\
             println(join(\"/usr\", \"lib\"))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    let stdout = String::from_utf8_lossy(&output.stdout);
    let expected = "true\n[a, b, c]\n1\n10\n-1\nfoo.txt\n/usr/lib\n.txt\n/usr/lib\n()\n";
    assert_eq!(stdout, expected, "stdout mismatch:\n{stdout}");
}

/// Extension methods (PR B): `extension (this: T) { def name() = ... }`
/// declarations add new methods to existing types and are dispatched
/// through dot syntax. The implicit `this` is in scope inside every
/// method body so members can be tiny one-liners.
#[test]
fn extension_methods_dispatch_via_dot_syntax() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "extension (this: String) {\n  \
               def shout() = toUpperCase(this)\n  \
               def repeatN(n) = if((n <= 0)) \"\" else this + this.repeatN(n - 1)\n\
             }\n\
             println(\"hi\".shout())\n\
             println(\"ab\".repeatN(3))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&output.stdout), "HI\nababab\n()\n");
}

/// A generic extension binds its type parameter `a` once across the
/// receiver and the method bodies, so `[1 2 3].headOr(0)` and
/// `["x" "y"].headOr("")` both compile from one declaration.
#[test]
fn generic_extension_methods_unify_type_parameter() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "extension <a>(this: List<a>) {\n  \
               def headOr(d) = if(isEmpty(this)) d else head(this)\n\
             }\n\
             println([1 2 3].headOr(0))\n\
             println([].headOr(99))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&output.stdout), "1\n99\n()\n");
}

/// Extension methods on a concrete instantiation of a generic type
/// (`List<Int>` here). The dispatch key normalises the receiver type
/// to its outer constructor, so the method is reachable from any
/// `List<Int>` value.
#[test]
fn extension_methods_dispatch_on_list_int() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "extension (this: List<Int>) {\n  \
               def total() = foldLeft(this)(0)((a, b) => a + b)\n\
             }\n\
             println([1 2 3 4 5].total())",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&output.stdout), "15\n()\n");
}

/// Extension-method dispatch unifies the receiver against the declared
/// `this` type, so the receiver's concrete type arguments are honoured.
/// A concrete `extension (this: List<Int>)` no longer applies to a
/// `List<String>`, and a generic `extension <a>(this: Box<a>)` binds `a`
/// to the receiver's element type — so an ill-typed argument is rejected
/// instead of being silently accepted (the result used to be typed at the
/// wrong argument, e.g. `Option<Int>.getOrElse("x")` returning a String).
#[test]
fn extension_method_dispatch_checks_receiver_type_arguments() {
    // A concrete `List<Int>` extension does not apply to a `List<String>`.
    let wrong_element = Command::new(klassic_bin())
        .args([
            "-e",
            "extension (this: List<Int>) { def headInt(): Int = head(this) }\n\
             val strs: List<String> = [\"hello\"]\n\
             val n: Int = strs.headInt()\n\
             println(n + 100)",
        ])
        .output()
        .expect("binary should run");
    assert!(
        !wrong_element.status.success(),
        "a List<Int> extension must not apply to a List<String>"
    );
    assert!(
        String::from_utf8_lossy(&wrong_element.stderr).contains("headInt"),
        "expected a no-such-method diagnostic, got:\n{}",
        String::from_utf8_lossy(&wrong_element.stderr)
    );

    // A generic extension binds `a` to the receiver's element type, so a
    // wrong-typed argument is a type error.
    let wrong_arg = Command::new(klassic_bin())
        .args([
            "-e",
            "enum Box<a> { case Full(v: a); case Empty }\n\
             extension <a>(this: Box<a>) { def getOr(v: a): a = this match { case Full(x) => x; case Empty => v } }\n\
             val b: Box<Int> = Empty\n\
             println(b.getOr(\"STR\"))",
        ])
        .output()
        .expect("binary should run");
    assert!(
        !wrong_arg.status.success(),
        "Box<Int>.getOr must reject a String argument"
    );
    assert!(
        String::from_utf8_lossy(&wrong_arg.stderr).contains("not compatible"),
        "expected a type-mismatch diagnostic, got:\n{}",
        String::from_utf8_lossy(&wrong_arg.stderr)
    );

    // Correct usage still compiles and runs: the matching concrete receiver
    // and the generic extension at its real element type both work.
    let correct = Command::new(klassic_bin())
        .args([
            "-e",
            "enum Box<a> { case Full(v: a); case Empty }\n\
             extension <a>(this: Box<a>) { def getOr(v: a): a = this match { case Full(x) => x; case Empty => v } }\n\
             val b: Box<Int> = Full(7)\n\
             println(b.getOr(0))",
        ])
        .output()
        .expect("binary should run");
    assert!(
        correct.status.success(),
        "correct extension usage must still work\nstderr:\n{}",
        String::from_utf8_lossy(&correct.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&correct.stdout), "7\n()\n");
}

/// Native build now supports extension methods on built-in types by
/// desugaring `extension (this: T) { def m() = ... }` into a
/// mangled top-level def `__ext_T_m(this) = ...` and rewriting
/// `target.m(args)` call sites with an unambiguous method name to
/// `__ext_T_m(target, args)`. The resulting binary executes the
/// extension body just like an inlined free function.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn native_build_compiles_extension_method_calls() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_native_ext_{stamp}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_native_ext_{stamp}.bin"));
    fs::write(
        &source_path,
        "extension (this: String) { def shout() = toUpperCase(this) }\nprintln(\"hi\".shout())\n",
    )
    .expect("temp source file should write");

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("source path should be utf-8"),
            "-o",
            output_path.to_str().expect("output path should be utf-8"),
        ])
        .output()
        .expect("binary should run");

    assert!(
        build_output.status.success(),
        "native build should succeed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stdout),
        String::from_utf8_lossy(&build_output.stderr)
    );

    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");

    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);

    assert!(
        run_output.status.success(),
        "compiled binary should exit cleanly\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&run_output.stdout),
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), "HI\n");
}

/// Native build now lowers monomorphic `enum` declarations, variant
/// constructors and `match` expressions onto the existing `__gc_*` heap
/// primitives: an enum value is a `__gc_record(1 + fields)` whose slot 0
/// holds the boxed variant tag. This covers nullary variants and
/// integer payloads end to end.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn native_build_compiles_enum_construction_and_match() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_native_enum_{stamp}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_native_enum_{stamp}.bin"));
    fs::write(
        &source_path,
        "enum Shape { case Circle(r: Int); case Square(side: Int); case Nothing }\n\
         def area(s) = s match {\n  \
           case Circle(r) => r * r * 3\n  \
           case Square(side) => side * side\n  \
           case Nothing => 0\n\
         }\n\
         println(area(Circle(2)))\n\
         println(area(Square(3)))\n\
         println(area(Nothing))\n",
    )
    .expect("temp source file should write");

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("source path should be utf-8"),
            "-o",
            output_path.to_str().expect("output path should be utf-8"),
        ])
        .output()
        .expect("binary should run");

    assert!(
        build_output.status.success(),
        "native build should succeed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stdout),
        String::from_utf8_lossy(&build_output.stderr)
    );

    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");

    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);

    assert!(
        run_output.status.success(),
        "compiled binary should exit cleanly\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&run_output.stdout),
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), "12\n9\n0\n");
}

/// Boolean enum payloads compile too: they are boxed as 0/1 integers on
/// construction and re-derived as `Bool` on extraction, so both
/// boolean-literal patterns (`case Mk(true, n)`) and bound boolean
/// variables work.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn native_build_compiles_boolean_enum_payloads() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_native_enumbool_{stamp}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_native_enumbool_{stamp}.bin"));
    fs::write(
        &source_path,
        "enum Flag { case Mk(active: Bool, level: Int) }\n\
         def describe(f) = f match {\n  \
           case Mk(true, n) => n\n  \
           case Mk(false, n) => 0 - n\n\
         }\n\
         println(describe(Mk(true, 5)))\n\
         println(describe(Mk(false, 5)))\n",
    )
    .expect("temp source file should write");

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("source path should be utf-8"),
            "-o",
            output_path.to_str().expect("output path should be utf-8"),
        ])
        .output()
        .expect("binary should run");

    assert!(
        build_output.status.success(),
        "native build should succeed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stdout),
        String::from_utf8_lossy(&build_output.stderr)
    );

    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");

    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);

    assert!(
        run_output.status.success(),
        "compiled binary should exit cleanly\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&run_output.stdout),
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), "5\n-5\n");
}

/// String enum payloads compile: a string field is normalized to a GC
/// heap string on construction and read back as one, so it can be bound
/// and returned (the `match` desugars to an `if` whose branches are
/// merged as heap strings) and matched against string literals.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn native_build_compiles_string_enum_payloads() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_native_enumstr_{stamp}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_native_enumstr_{stamp}.bin"));
    fs::write(
        &source_path,
        "enum Tag { case Named(s: String); case Anon }\n\
         def show(t) = t match { case Named(s) => s; case Anon => \"anon\" }\n\
         def kind(t) = t match { case Named(\"x\") => 1; case Named(other) => 2; case Anon => 0 }\n\
         println(show(Named(\"hello\")))\n\
         println(show(Anon))\n\
         println(kind(Named(\"x\")))\n\
         println(kind(Named(\"y\")))\n\
         println(kind(Anon))\n",
    )
    .expect("temp source file should write");

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("source path should be utf-8"),
            "-o",
            output_path.to_str().expect("output path should be utf-8"),
        ])
        .output()
        .expect("binary should run");

    assert!(
        build_output.status.success(),
        "native build should succeed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stdout),
        String::from_utf8_lossy(&build_output.stderr)
    );

    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");

    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);

    assert!(
        run_output.status.success(),
        "compiled binary should exit cleanly\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&run_output.stdout),
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&run_output.stdout),
        "hello\nanon\n1\n2\n0\n"
    );
}

/// Native `match` lowering is fully recursive: nested constructor
/// patterns (`case O(I(n))`), integer-literal sub-patterns and arm
/// guards all compile, with short-circuited tag tests guarding payload
/// reads so a mismatched variant never dereferences a slot it lacks.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn native_build_compiles_nested_enum_patterns_with_guards() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_native_enum_nest_{stamp}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_native_enum_nest_{stamp}.bin"));
    fs::write(
        &source_path,
        "enum Inner { case I(n: Int) }\n\
         enum Outer { case O(inner: Inner); case Empty }\n\
         def g(o) = o match {\n  \
           case O(I(0)) => -100\n  \
           case O(I(n)) if n > 10 => n * 2\n  \
           case O(I(n)) => n\n  \
           case Empty => -1\n\
         }\n\
         println(g(O(I(0))))\n\
         println(g(O(I(20))))\n\
         println(g(O(I(5))))\n\
         println(g(Empty))\n",
    )
    .expect("temp source file should write");

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("source path should be utf-8"),
            "-o",
            output_path.to_str().expect("output path should be utf-8"),
        ])
        .output()
        .expect("binary should run");

    assert!(
        build_output.status.success(),
        "native build should succeed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stdout),
        String::from_utf8_lossy(&build_output.stderr)
    );

    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");

    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);

    assert!(
        run_output.status.success(),
        "compiled binary should exit cleanly\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&run_output.stdout),
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&run_output.stdout),
        "-100\n40\n5\n-1\n"
    );
}

