/// `else` may start a continuation line (GitHub issue #429): the if
/// parser peeks past newline tokens and only consumes them when an
/// `else` actually follows, so the newline still terminates the
/// expression otherwise. Covers else-if chains, eval and native.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn else_continues_on_the_next_line() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_else_line_{stamp}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_else_line_{stamp}.bin"));
    fs::write(
        &source_path,
        "def g(x: Int): Int =\n\
           if (x > 10) 100\n\
           else if (x > 5) 50\n\
           else 0\n\
         println(g(20))\n\
         println(g(7))\n\
         println(g(1))\n",
    )
    .expect("temp source file should write");
    let expected = "100\n50\n0\n";

    let eval_output = Command::new(klassic_bin())
        .arg(source_path.to_str().expect("path should be utf-8"))
        .output()
        .expect("binary should run");
    assert!(
        eval_output.status.success(),
        "continuation else should parse\nstderr:\n{}",
        String::from_utf8_lossy(&eval_output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&eval_output.stdout), expected);

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            output_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "continuation else should compile natively\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);
    assert!(run_output.status.success());
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), expected);
}

/// Top-level defs can forward-reference each other (GitHub issue
/// #427): the type checker predeclares every unconstrained def in a
/// block before checking statements (retiring the monomorphic
/// predeclaration before generalizing so polymorphic helpers stay
/// polymorphic), and the evaluator seeds shared placeholder cells so
/// an early closure's environment snapshot sees later sibling
/// definitions. Covers eval and native.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn top_level_defs_support_mutual_recursion() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_mutual_rec_{stamp}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_mutual_rec_{stamp}.bin"));
    fs::write(
        &source_path,
        "def isEven(n: Int): Bool = if (n == 0) true else isOdd(n - 1)\n\
         def isOdd(n: Int): Bool = if (n == 0) false else isEven(n - 1)\n\
         println(isEven(10))\n\
         println(isOdd(7))\n",
    )
    .expect("temp source file should write");
    let expected = "true\ntrue\n";

    let eval_output = Command::new(klassic_bin())
        .arg(source_path.to_str().expect("path should be utf-8"))
        .output()
        .expect("binary should run");
    assert!(
        eval_output.status.success(),
        "mutual recursion should evaluate\nstderr:\n{}",
        String::from_utf8_lossy(&eval_output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&eval_output.stdout), expected);

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            output_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "mutual recursion should compile natively\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);
    assert!(run_output.status.success());
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), expected);
}

/// The direct aarch64-apple-darwin backend cross-builds from any
/// host: `--target aarch64-apple-darwin` produces a signed Mach-O
/// arm64 image. This structural check runs everywhere; actual
/// execution is asserted by the macOS-gated test below.
#[test]
fn build_target_aarch64_apple_darwin_emits_macho() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_macho_{stamp}.kl"));
    let bin_path = dir.join(format!("klassic_macho_{stamp}.bin"));
    fs::write(&source_path, "println(\"hello mac\")\nprintln(7)\n")
        .expect("temp source file should write");
    let build_output = Command::new(klassic_bin())
        .args([
            "--target",
            "aarch64-apple-darwin",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            bin_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "darwin cross build should succeed\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let image = fs::read(&bin_path).expect("output should exist");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&bin_path);
    // MH_MAGIC_64 + CPU_TYPE_ARM64, and the embedded ad-hoc code
    // signature SuperBlob magic must terminate the file.
    assert_eq!(&image[0..4], &0xfeed_facf_u32.to_le_bytes());
    assert_eq!(&image[4..8], &0x0100_000c_u32.to_le_bytes());
    assert!(
        image
            .windows(4)
            .any(|window| window == 0xfade_0cc0_u32.to_be_bytes()),
        "embedded signature SuperBlob missing"
    );
}

/// Regression guard that runs on any host (including the fast Linux CI
/// job): the aarch64 cross-build must accept monomorphic enum
/// construction and match. The shared enum-lowering pass wraps
/// constructions in shape-marker calls (`__enum_shape_named`) for the
/// x86_64 display/dispatch paths; if those leak unhandled into the
/// aarch64 backend, every enum build fails — a class of regression
/// previously caught only by the macOS-gated run test.
#[test]
fn build_target_aarch64_apple_darwin_enum_cross_build() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_macho_enum_xbuild_{stamp}.kl"));
    let bin_path = dir.join(format!("klassic_macho_enum_xbuild_{stamp}.bin"));
    fs::write(
        &source_path,
        "enum Tree { case Leaf(v: Int); case Branch(l: Tree, r: Tree) }\n\
         def total(t: Tree): Int = t match { case Leaf(v) => v; case Branch(l, r) => total(l) + total(r) }\n\
         val t = Branch(Leaf(7), Leaf(2))\n\
         println(total(t))\n",
    )
    .expect("temp source file should write");
    let build_output = Command::new(klassic_bin())
        .args([
            "--target",
            "aarch64-apple-darwin",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            bin_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&bin_path);
    assert!(
        build_output.status.success(),
        "darwin enum cross build should succeed\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
}

/// On an Apple Silicon mac the generated Mach-O actually runs — this
/// is the acceptance test for the M1 slice of the direct aarch64
/// backend (it executes on macOS CI's arm64 runners).
#[cfg(all(target_os = "macos", target_arch = "aarch64"))]
#[test]
fn build_target_aarch64_apple_darwin_binary_runs() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_macho_run_{stamp}.kl"));
    let bin_path = dir.join(format!("klassic_macho_run_{stamp}.bin"));
    fs::write(
        &source_path,
        "val a = 6\n\
         mutable i = 0\n\
         mutable total = 0\n\
         while (i < 10) {\n\
           total = total + i\n\
           i = i + 1\n\
         }\n\
         println(\"hello from klassic on apple silicon\")\n\
         println(total)\n\
         println(a * 7)\n\
         println(0 - a)\n\
         println(if (total > 40) 111 else 222)\n\
         println(total == 45)\n\
         println(i >= 10 && a < 7)\n\
         println(false || total < 0)\n\
         println(100000000 / 7)\n\
         println(2.5)\n",
    )
    .expect("temp source file should write");
    let build_output = Command::new(klassic_bin())
        .args([
            "--target",
            "aarch64-apple-darwin",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            bin_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "darwin native build should succeed\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let run_output = Command::new(&bin_path)
        .output()
        .expect("generated Mach-O should execute");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&bin_path);
    assert!(
        run_output.status.success(),
        "Mach-O exited with {:?}\nstderr:\n{}",
        run_output.status,
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&run_output.stdout),
        "hello from klassic on apple silicon\n45\n42\n-6\n111\ntrue\ntrue\nfalse\n14285714\n2.5\n"
    );
}

