/// M15 acceptance test: directory ops actually run on an Apple
/// Silicon mac, matching the evaluator's output exactly.
#[cfg(all(target_os = "macos", target_arch = "aarch64"))]
#[test]
fn build_target_aarch64_apple_darwin_dir_ops_runs() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_macho_dirops_run_{stamp}.kl"));
    let bin_path = dir.join(format!("klassic_macho_dirops_run_{stamp}.bin"));
    let nested_path = dir.join(format!("klassic_macho_dirops_run_nested_{stamp}/a/b"));
    let base_path = dir.join(format!("klassic_macho_dirops_run_nested_{stamp}"));
    let moved_path = dir.join(format!("klassic_macho_dirops_run_moved_{stamp}"));
    let plain_file_path = dir.join(format!("klassic_macho_dirops_run_file_{stamp}.txt"));
    let missing_path = dir.join(format!("klassic_macho_dirops_run_missing_{stamp}"));
    let nested = nested_path.display().to_string().replace('\\', "\\\\");
    let moved = moved_path.display().to_string().replace('\\', "\\\\");
    let plain_file = plain_file_path.display().to_string().replace('\\', "\\\\");
    let missing = missing_path.display().to_string().replace('\\', "\\\\");
    fs::write(
        &source_path,
        format!(
            "Dir#mkdirs(\"{nested}\")\n\
             println(Dir#exists(\"{nested}\"))\n\
             println(Dir#isDirectory(\"{nested}\"))\n\
             Dir#move(\"{nested}\", \"{moved}\")\n\
             println(Dir#exists(\"{nested}\"))\n\
             println(Dir#isDirectory(\"{moved}\"))\n\
             FileOutput#write(\"{plain_file}\", \"x\\n\")\n\
             println(Dir#isDirectory(\"{plain_file}\"))\n\
             println(Dir#isDirectory(\"{missing}\"))\n\
             FileOutput#delete(\"{plain_file}\")\n\
             Dir#delete(\"{moved}\")\n\
             println(\"dir-ops-ok\")\n",
        ),
    )
    .expect("temp source file should write");
    let build_output = Command::new(klassic_bin())
        .args([
            "--target",
            "aarch64-apple-darwin",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            bin_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "darwin dir ops build should succeed\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let run_output = Command::new(&bin_path)
        .output()
        .expect("generated Mach-O should execute");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&bin_path);
    let _ = fs::remove_dir_all(&base_path);
    let _ = fs::remove_dir_all(&moved_path);
    let _ = fs::remove_file(&plain_file_path);
    assert!(
        run_output.status.success(),
        "Mach-O exited with {:?}\nstderr:\n{}",
        run_output.status,
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&run_output.stdout),
        "true\ntrue\nfalse\ntrue\nfalse\nfalse\ndir-ops-ok\n"
    );
}

/// Regression guard on any host: `Environment#exists` and
/// `Time#nowMillis` must cross-build for aarch64-apple-darwin -- M16
/// (issue #538), which also captures argc/argv/envp from dyld's
/// LC_MAIN entry in the program prologue. `Time#nowMillis` was
/// attempted once before and withdrawn after a real-hardware crash
/// (see issue #570): the actual root cause turned out to be calling
/// `gettimeofday` (syscall 116) with only 2 arguments when
/// `syscalls.master` (apple-oss-distributions/xnu) defines it as a
/// 3-argument, `NO_SYSCALL_STUB` syscall -- `int gettimeofday(struct
/// timeval *tp, struct timezone *tzp, uint64_t *mach_absolute_time)`
/// -- leaving x2 (the third argument) holding whatever garbage a
/// prior computation left there, which the kernel likely
/// misinterpreted as a pointer to write `mach_absolute_time`
/// through. This attempt explicitly zeroes x2 before the trap.
#[test]
fn build_target_aarch64_apple_darwin_env_time_cross_build() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_macho_envtime_xbuild_{stamp}.kl"));
    let bin_path = dir.join(format!("klassic_macho_envtime_xbuild_{stamp}.bin"));
    fs::write(
        &source_path,
        "val t = Time#nowMillis()\n\
         println(t > 1700000000000)\n\
         println(t < 3000000000000)\n\
         println(Environment#exists(\"KLASSIC_ENV_TIME_TEST_NONEXISTENT_XYZ\"))\n\
         println(Environment#exists(\"PATH\"))\n",
    )
    .expect("temp source file should write");
    let build_output = Command::new(klassic_bin())
        .args([
            "--target",
            "aarch64-apple-darwin",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            bin_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&bin_path);
    assert!(
        build_output.status.success(),
        "darwin env/time cross build should succeed\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
}

/// M16 acceptance test: `Environment#exists` and `Time#nowMillis`
/// actually run on an Apple Silicon mac. `Time#nowMillis` can't be
/// compared byte-for-byte against the evaluator (real time elapses
/// between the two runs), so this checks the value falls in a sane
/// range instead -- this is also the real-hardware re-verification of
/// the 3-argument `gettimeofday` fix, on the exact class of test
/// (`Time#nowMillis` called first, forcing its `gettimeofday` to be
/// the very first heap allocation in the program) that caught the
/// SIGSEGV the first time.
#[cfg(all(target_os = "macos", target_arch = "aarch64"))]
#[test]
fn build_target_aarch64_apple_darwin_env_time_runs() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_macho_envtime_run_{stamp}.kl"));
    let bin_path = dir.join(format!("klassic_macho_envtime_run_{stamp}.bin"));
    fs::write(
        &source_path,
        "val t = Time#nowMillis()\n\
         println(t > 1700000000000)\n\
         println(t < 3000000000000)\n\
         println(Environment#exists(\"KLASSIC_ENV_TIME_TEST_NONEXISTENT_XYZ\"))\n\
         println(Environment#exists(\"PATH\"))\n",
    )
    .expect("temp source file should write");
    let build_output = Command::new(klassic_bin())
        .args([
            "--target",
            "aarch64-apple-darwin",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            bin_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "darwin env/time build should succeed\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let run_output = Command::new(&bin_path)
        .output()
        .expect("generated Mach-O should execute");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&bin_path);
    assert!(
        run_output.status.success(),
        "Mach-O exited with {:?} (a SIGSEGV here means the 3-argument \
         gettimeofday fix didn't hold)\nstderr:\n{}",
        run_output.status,
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&run_output.stdout),
        "true\ntrue\nfalse\ntrue\n"
    );
}

/// On Apple Silicon a target-less `build` detects the host: programs
/// inside the direct subset get the toolchain-free Mach-O backend
/// (no libSystem linkage), and programs outside it silently fall
/// back to the portable C backend. Both must run correctly.
#[cfg(all(target_os = "macos", target_arch = "aarch64"))]
#[test]
fn build_host_default_uses_direct_backend_with_c_fallback() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();

    // Direct-subset program: must come out of the direct backend.
    let direct_source = dir.join(format!("klassic_hostdetect_a_{stamp}.kl"));
    let direct_bin = dir.join(format!("klassic_hostdetect_a_{stamp}.bin"));
    fs::write(
        &direct_source,
        "def fib(n: Int): Int = if (n < 2) n else fib(n - 1) + fib(n - 2)\nprintln(fib(20))\n",
    )
    .expect("temp source file should write");
    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            direct_source.to_str().expect("path should be utf-8"),
            "-o",
            direct_bin.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "host-default build should succeed\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let image = fs::read(&direct_bin).expect("output should exist");
    assert!(
        !image
            .windows(b"libSystem".len())
            .any(|window| window == b"libSystem"),
        "direct-subset program should not be cc-linked"
    );
    let run_output = Command::new(&direct_bin)
        .output()
        .expect("direct binary should run");
    let _ = fs::remove_file(&direct_source);
    let _ = fs::remove_file(&direct_bin);
    assert!(run_output.status.success());
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), "6765\n");

    // String-manipulating program: outside the direct subset, so the
    // C fallback (cc + bundled runtime) must kick in transparently.
    let cc_available = Command::new("cc")
        .arg("--version")
        .output()
        .is_ok_and(|probe| probe.status.success());
    if !cc_available {
        return;
    }
    let fallback_source = dir.join(format!("klassic_hostdetect_b_{stamp}.kl"));
    let fallback_bin = dir.join(format!("klassic_hostdetect_b_{stamp}.bin"));
    // Double arithmetic stays outside the direct subset for now, so
    // this exercises the silent C fallback.
    fs::write(
        &fallback_source,
        "def area(r: Double): Double = r * r * 3.14159\nprintln(area(2.0))\n",
    )
    .expect("temp source file should write");
    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            fallback_source.to_str().expect("path should be utf-8"),
            "-o",
            fallback_bin.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "C fallback build should succeed\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let run_output = Command::new(&fallback_bin)
        .output()
        .expect("fallback binary should run");
    let _ = fs::remove_file(&fallback_source);
    let _ = fs::remove_file(&fallback_bin);
    assert!(run_output.status.success());
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), "12.56636\n");
}

/// A target-less `klassic build` must produce a binary the host can
/// actually execute. Linux x86_64 uses the direct ELF backend; hosts
/// without a direct backend (macOS CI) route through the portable C
/// backend automatically instead of silently emitting a Linux ELF
/// (the v0.2.0 "exec format error" regression).
#[test]
fn build_without_target_produces_runnable_host_binary() {
    // The C route needs a system C compiler; only required off Linux.
    if !cfg!(all(target_os = "linux", target_arch = "x86_64")) {
        let cc_available = Command::new("cc")
            .arg("--version")
            .output()
            .is_ok_and(|probe| probe.status.success());
        if !cc_available {
            return;
        }
    }
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_hostbuild_{stamp}.kl"));
    let bin_path = dir.join(format!("klassic_hostbuild_{stamp}.bin"));
    fs::write(
        &source_path,
        "def fib(n: Int): Int = if (n < 2) n else fib(n - 1) + fib(n - 2)\n\
         println(\"hello from \" + \"klassic\")\n\
         println(fib(15))\n",
    )
    .expect("temp source file should write");
    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            bin_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "target-less build should succeed on the host\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let run_output = Command::new(&bin_path)
        .output()
        .expect("compiled binary should run on the host");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&bin_path);
    assert!(run_output.status.success());
    assert_eq!(
        String::from_utf8_lossy(&run_output.stdout),
        "hello from klassic\n610\n"
    );
}

/// The C backend's string surface (roadmap PR 10): strings are KStr
/// values served by the klassic_rt_* shims in libklassic_runtime.a,
/// sharing semantics with the evaluator — character-counted length,
/// char-indexed substring/at, concat, equality, toString. The test
/// compiles and links through the automatic cc path and compares
/// against the evaluator's output.
#[cfg(unix)]
#[test]
fn build_backend_c_strings_match_the_evaluator() {
    let cc_available = Command::new("cc")
        .arg("--version")
        .output()
        .is_ok_and(|probe| probe.status.success());
    if !cc_available {
        return;
    }
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_cstrings_{stamp}.kl"));
    let bin_path = dir.join(format!("klassic_cstrings_{stamp}.bin"));
    fs::write(
        &source_path,
        "def greet(name: String): String = \"hello, \" + name + \"!\"\n\
         def shout(s: String, n: Int): String = if (n <= 0) s else shout(s + \"!\", n - 1)\n\
         def area(r: Double): Double = r * r * 3.14159\n\
         println(greet(\"klassic\"))\n\
         println(length(\"あいう\"))\n\
         println(substring(\"hello world\", 6, 11))\n\
         println(at(\"abc\", 1))\n\
         println(greet(\"a\") == \"hello, a!\")\n\
         println(toString(42) + \"-\" + toString(true))\n\
         println(shout(\"hey\", 3))\n\
         println(area(2.0))\n\
         println(1.5 + 2.25)\n\
         println(toString(0.5) + \"!\")\n",
    )
    .expect("temp source file should write");
    let expected = "hello, klassic!\n3\nworld\nb\ntrue\n42-true\nhey!!!\n12.56636\n3.75\n0.5!\n";

    let eval_output = Command::new(klassic_bin())
        .arg(source_path.to_str().expect("path should be utf-8"))
        .output()
        .expect("binary should run");
    assert!(eval_output.status.success());
    assert_eq!(String::from_utf8_lossy(&eval_output.stdout), expected);

    let link_output = Command::new(klassic_bin())
        .args([
            "--backend",
            "c",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            bin_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        link_output.status.success(),
        "C backend should compile and link strings\nstderr:\n{}",
        String::from_utf8_lossy(&link_output.stderr)
    );
    let run_output = Command::new(&bin_path)
        .output()
        .expect("compiled C binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&bin_path);
    assert!(run_output.status.success());
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), expected);
}

/// The C backend renders `Double` values exactly like the evaluator: a
/// whole-number value keeps a single trailing decimal (`4.0`), not the
/// bare integer Rust's default `f64` formatting would emit. The earlier
/// runtime shim used `f64::to_string`, so a whole-number Double printed
/// as `4` while the evaluator (and the direct native backend) printed
/// `4.0`.
#[cfg(unix)]
#[test]
fn build_backend_c_formats_doubles_like_evaluator() {
    let cc_available = Command::new("cc")
        .arg("--version")
        .output()
        .is_ok_and(|probe| probe.status.success());
    if !cc_available {
        return;
    }
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_cdoubles_{stamp}.kl"));
    let bin_path = dir.join(format!("klassic_cdoubles_{stamp}.bin"));
    fs::write(
        &source_path,
        "println(4.0)\n\
         println(2.0 * 3.0)\n\
         println(0.0)\n\
         println(100.0)\n\
         println(10.0 / 2.0)\n\
         println(3.14)\n\
         println(1.5 + 2.25)\n",
    )
    .expect("temp source file should write");
    let expected = "4.0\n6.0\n0.0\n100.0\n5.0\n3.14\n3.75\n";

    let eval_output = Command::new(klassic_bin())
        .arg(source_path.to_str().expect("path should be utf-8"))
        .output()
        .expect("binary should run");
    assert!(eval_output.status.success());
    assert_eq!(
        String::from_utf8_lossy(&eval_output.stdout),
        expected,
        "evaluator oracle"
    );

    let link_output = Command::new(klassic_bin())
        .args([
            "--backend",
            "c",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            bin_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        link_output.status.success(),
        "C backend should compile doubles\nstderr:\n{}",
        String::from_utf8_lossy(&link_output.stderr)
    );
    let run_output = Command::new(&bin_path)
        .output()
        .expect("compiled C binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&bin_path);
    assert!(run_output.status.success());
    assert_eq!(
        String::from_utf8_lossy(&run_output.stdout),
        expected,
        "C backend double formatting must match the evaluator"
    );
}

/// The portable C backend (GitHub issue #425, roadmap PR 9) emits a
/// single C99 translation unit for the Int/Bool/String/println/if/
/// while/def subset behind `--backend c`. The generated source depends
/// only on stdio/stdint; when a `cc` is available the test compiles
/// and runs it and asserts evaluator-identical output. Unsupported
/// constructs get source-located diagnostics.
#[cfg(unix)]
#[test]
fn build_backend_c_emits_compilable_c() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir();
    let source_path = dir.join(format!("klassic_cbackend_{stamp}.kl"));
    let c_path = dir.join(format!("klassic_cbackend_{stamp}.c"));
    let bin_path = dir.join(format!("klassic_cbackend_{stamp}.bin"));
    fs::write(
        &source_path,
        "def fib(n: Int): Int = if (n < 2) n else fib(n - 1) + fib(n - 2)\n\
         def shout(flag: Bool): String = if (flag) \"yes\" else \"no\"\n\
         println(\"hello from klassic via C\")\n\
         println(fib(20))\n\
         println(shout(true))\n\
         mutable i = 0\n\
         mutable total = 0\n\
         while (i < 5) {\n\
           total = total + i\n\
           i = i + 1\n\
         }\n\
         println(total)\n\
         println(i == 5)\n",
    )
    .expect("temp source file should write");
    let expected = "hello from klassic via C\n6765\nyes\n10\ntrue\n";

    let build_output = Command::new(klassic_bin())
        .args([
            "--backend",
            "c",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            c_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "C backend should emit\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let c_source = fs::read_to_string(&c_path).expect("C output should exist");
    assert!(c_source.contains("int main(void)"), "{c_source}");
    assert!(
        c_source.contains("int64_t kl_fib(int64_t kl_n)"),
        "{c_source}"
    );

    let cc_available = Command::new("cc")
        .arg("--version")
        .output()
        .is_ok_and(|probe| probe.status.success());
    if cc_available {
        // A non-.c output compiles and links against the bundled
        // runtime staticlib automatically.
        let link_output = Command::new(klassic_bin())
            .args([
                "--backend",
                "c",
                "build",
                source_path.to_str().expect("path should be utf-8"),
                "-o",
                bin_path.to_str().expect("path should be utf-8"),
            ])
            .output()
            .expect("binary should run");
        assert!(
            link_output.status.success(),
            "C backend should compile and link\nstderr:\n{}",
            String::from_utf8_lossy(&link_output.stderr)
        );
        let run_output = Command::new(&bin_path)
            .output()
            .expect("compiled C binary should run");
        assert!(run_output.status.success());
        assert_eq!(String::from_utf8_lossy(&run_output.stdout), expected);
    }

    let unsupported = Command::new(klassic_bin())
        .args([
            "--backend",
            "c",
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            c_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(unsupported.status.success());

    let enum_source_path = dir.join(format!("klassic_cbackend_enum_{stamp}.kl"));
    fs::write(
        &enum_source_path,
        "enum Color { case Red }\nprintln(Red match { case Red => 1 })\n",
    )
    .expect("temp source file should write");
    let rejected = Command::new(klassic_bin())
        .args([
            "--backend",
            "c",
            "build",
            enum_source_path.to_str().expect("path should be utf-8"),
            "-o",
            c_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&enum_source_path);
    let _ = fs::remove_file(&c_path);
    let _ = fs::remove_file(&bin_path);
    assert!(!rejected.status.success());
    assert!(
        String::from_utf8_lossy(&rejected.stderr)
            .contains("not supported by the portable C backend yet"),
        "{}",
        String::from_utf8_lossy(&rejected.stderr)
    );
}

/// std.time wraps the Time#nowMillis builtin with ISO-8601 UTC
/// formatting (Hinnant's days-to-civil on integer arithmetic) and
/// duration helpers, in pure Klassic — parity-tested across the
/// evaluator and a native build (GitHub issue #423).
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn std_time_formats_iso_in_evaluator_and_native() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_std_time_{stamp}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_std_time_{stamp}.bin"));
    fs::write(
        &source_path,
        "import std.time.{formatIso, nowMillis, durationMillis}\n\
         println(formatIso(0))\n\
         println(formatIso(1718000000123))\n\
         println(formatIso(951827696789))\n\
         println(durationMillis(100, 350))\n\
         println(nowMillis() > 1718000000000)\n",
    )
    .expect("temp source file should write");
    let expected = "1970-01-01T00:00:00.000Z\n\
                    2024-06-10T06:13:20.123Z\n\
                    2000-02-29T12:34:56.789Z\n\
                    250\n\
                    true\n";

    let eval_output = Command::new(klassic_bin())
        .arg(source_path.to_str().expect("path should be utf-8"))
        .output()
        .expect("binary should run");
    assert!(
        eval_output.status.success(),
        "std.time should evaluate\nstderr:\n{}",
        String::from_utf8_lossy(&eval_output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&eval_output.stdout), expected);

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("path should be utf-8"),
            "-o",
            output_path.to_str().expect("path should be utf-8"),
        ])
        .output()
        .expect("binary should run");
    assert!(
        build_output.status.success(),
        "std.time should compile natively\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stderr)
    );
    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");
    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);
    assert!(run_output.status.success());
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), expected);
}

/// `.toString()` works on an inferred (still-unresolved) receiver
/// (GitHub issue #428): the builtin-method lookup answers for type
/// variables without unifying the receiver into a structural record,
/// so an Int parameter used as `i.toString()` stays an Int and a
/// polymorphic helper serves every value kind.
#[test]
fn to_string_works_on_inferred_receivers() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "def fail(message, i) = message + \" at position \" + i.toString()\n\
             def show(x) = x.toString()\n\
             println(fail(\"oops\", 42))\n\
             println(show(7))\n\
             println(show(\"hi\"))\n\
             println(show(true))",
        ])
        .output()
        .expect("binary should run");
    assert!(
        output.status.success(),
        "inferred-receiver toString should typecheck\nstderr:\n{}",
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        "oops at position 42\n7\nhi\ntrue\n()\n"
    );
}

/// std.json parses and renders JSON (GitHub issue #422): objects,
/// arrays, negative integers, escapes, and nesting round-trip;
/// malformed input returns Err with a character position instead of
/// aborting. Written in pure Klassic on top of the ADT/stdlib stack.
#[test]
fn evaluator_parses_and_stringifies_json() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "import std.json.{parse, stringify}\n\
             import std.result.{ok, err}\n\
             def show(text) = parse(text) match { case Ok(j) => stringify(j); case Err(e) => \"ERR: \" + e }\n\
             println(show(\"  [ -42, true, false, \\\"a\\\\nb\\\\\\\"c\\\", {} ]  \"))\n\
             println(show(\"{\\\"nested\\\": {\\\"deep\\\": [[1], []]}}\"))\n\
             println(show(\"[1, 2\"))\n\
             println(show(\"[1] garbage\"))",
        ])
        .output()
        .expect("binary should run");
    assert!(
        output.status.success(),
        "json module should evaluate\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        "[-42,true,false,\"a\\nb\\\"c\",{}]\n\
         {\"nested\":{\"deep\":[[1],[]]}}\n\
         ERR: expected `,` or `]` at position 5\n\
         ERR: trailing input at position 4\n\
         ()\n"
    );
}

/// Stdlib v0.2 ships ADT-based Option / Result modules. Both expose
/// pattern matching via `match` so callers stay decoupled from the
/// underlying representation.
#[test]
fn evaluator_imports_std_option_and_result() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "import std.option.{some, none, getOrElse}\n\
             println(getOrElse(some(\"hi\"), \"fallback\"))\n\
             println(getOrElse(none, \"fallback\"))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        "hi\nfallback\n()\n"
    );
}

/// `enum` declarations + postfix `match` form the v0.2 ADT surface.
/// Variants build values via constructor calls; `x match { case ... }`
/// destructures them and binds positional pattern variables in scope.
#[test]
fn evaluator_supports_enum_declarations_and_postfix_match() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "enum Option<a> { case Some(v: a); case None }\n\
             def describe(o) = o match {\n  \
               case Some(n) => \"got \" + toString(n)\n  \
               case None => \"nothing\"\n\
             }\n\
             println(describe(Some(42)))\n\
             println(describe(None))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        "got 42\nnothing\n()\n"
    );
}

/// The shipped `examples/stdlib-v0.2-demo.kl` script exercises the
/// full v0.2 surface — extension methods on List / String / Int /
/// Map plus an ADT `match`. Pinning its expected stdout means any
/// stdlib regression that touches one of those areas trips here.
#[test]
fn stdlib_v0_2_demo_example_round_trips_end_to_end() {
    let demo_path = std::env::current_dir()
        .expect("current dir should be readable")
        .join("examples/stdlib-v0.2-demo.kl");
    let output = Command::new(klassic_bin())
        .arg(demo_path.to_str().expect("path should be utf-8"))
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        concat!(
            "55\n",
            "3628800\n",
            "HELLO, KLASSIC!\n",
            "spaces\n",
            "[alpha:beta:gamma]\n",
            "true\n",
            "10\n",
            "7\n",
            "55\n",
            "[2, 4, 6, 8, 10]\n",
            "true\n",
            "0\n",
            "2\n",
            "42\n",
            "got 42\n",
        )
    );
}

/// Recursive ADTs (linked list, tree) work end to end: declarations
/// install their constructors, `match` arms bind fields with the
/// right type, and recursive helpers terminate.
#[test]
fn evaluator_handles_recursive_enums() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "enum Tree { case Leaf(value: Int); case Branch(left: Tree, right: Tree) }\n\
             def total(t) = t match {\n  \
               case Leaf(v) => v\n  \
               case Branch(l, r) => total(l) + total(r)\n\
             }\n\
             val t = Branch(Leaf(1), Branch(Leaf(2), Leaf(3)))\n\
             println(total(t))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&output.stdout), "6\n()\n");
}

/// Wildcard `case _ => ...` catches every variant that does not
/// match an earlier arm. The arm reports the variant name via
/// `toString` so callers can sanity-check the runtime tag.
#[test]
fn evaluator_match_wildcard_arm_catches_unmatched_variant() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "enum Color { case Red; case Green; case Blue }\n\
             val c = Green\n\
             val name = c match {\n  \
               case Red => \"red\"\n  \
               case _   => \"other\"\n\
             }\n\
             println(name)",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&output.stdout), "other\n()\n");
}

/// Enum extension methods round-trip through dot syntax — both
/// `Option<a>` and `Result<a, e>` work via either the function-style
/// helpers or the extension-method form.
#[test]
fn evaluator_enum_extension_methods_round_trip() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "import std.result.{ok, err}\n\
             println(ok(\"yes\").isOk())\n\
             println(err(\"boom\").isErr())\n\
             println(ok(\"yes\").unwrapOr(\"fallback\"))\n\
             println(err(\"boom\").unwrapOr(\"fallback\"))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        "true\ntrue\nyes\nfallback\n()\n"
    );
}

/// `std.test` provides named assertion helpers that print a
/// human-readable `[ OK ]` / `[FAIL]` line each. Failing checks go
/// to stderr; passing ones go to stdout — and unlike the raw
/// `assert` builtin, neither aborts the script.
#[test]
fn evaluator_uses_std_test_assertions() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "import std.test.{expectTrue, expectEqualsInt}\n\
             expectTrue(\"truthy\", true)\n\
             expectEqualsInt(\"math\", 6, 1 + 2 + 3)\n\
             expectEqualsInt(\"fails\", 99, 1)",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    let stdout = String::from_utf8_lossy(&output.stdout);
    assert!(stdout.contains("[ OK ] truthy"), "stdout: {stdout}");
    assert!(stdout.contains("[ OK ] math"), "stdout: {stdout}");
    let stderr = String::from_utf8_lossy(&output.stderr);
    assert!(stderr.contains("[FAIL] fails"), "stderr: {stderr}");
}

/// `std.cli` cooperates with the new `klassic run file.kl -- args`
/// path: `flag`, `option`, and `positionals` operate on the list
/// `CommandLine#args()` returns after the `--` separator.
#[test]
fn evaluator_uses_std_cli_helpers() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_std_cli_{stamp}.kl"));
    fs::write(
        &source_path,
        "import std.cli.{flag, option, positionals}\n\
         val args = CommandLine#args()\n\
         println(flag(args, \"--verbose\"))\n\
         println(option(args, \"--out\"))\n\
         println(positionals(args))\n",
    )
    .expect("temp source file should write");

    let output = Command::new(klassic_bin())
        .args([
            "run",
            source_path.to_str().expect("source path should be utf-8"),
            "--",
            "--verbose",
            "--out",
            "file.txt",
            "input.txt",
        ])
        .output()
        .expect("binary should run");

    let _ = fs::remove_file(&source_path);

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        "true\nfile.txt\n[file.txt, input.txt]\n"
    );
}

/// Native build inlines a plain-Klassic `std.*` import (formerly
/// rejected with a "not yet available in native builds" diagnostic):
/// `import std.list.{range}` splices `range` into the program and the
/// compiled binary prints the list.
#[cfg(all(target_os = "linux", target_arch = "x86_64"))]
#[test]
fn native_build_inlines_std_list_import() {
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("system time should be after epoch")
        .as_nanos();
    let source_path = std::env::temp_dir().join(format!("klassic_std_native_{stamp}.kl"));
    let output_path = std::env::temp_dir().join(format!("klassic_std_native_{stamp}.bin"));
    fs::write(
        &source_path,
        "import std.list.{range}\nprintln(range(0, 3))\n",
    )
    .expect("temp source file should write");

    let build_output = Command::new(klassic_bin())
        .args([
            "build",
            source_path.to_str().expect("source path should be utf-8"),
            "-o",
            output_path.to_str().expect("output path should be utf-8"),
        ])
        .output()
        .expect("binary should run");

    assert!(
        build_output.status.success(),
        "native build should succeed\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&build_output.stdout),
        String::from_utf8_lossy(&build_output.stderr)
    );

    let run_output = Command::new(&output_path)
        .output()
        .expect("compiled binary should run");

    let _ = fs::remove_file(&source_path);
    let _ = fs::remove_file(&output_path);

    assert!(
        run_output.status.success(),
        "compiled binary should exit cleanly\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&run_output.stdout),
        String::from_utf8_lossy(&run_output.stderr)
    );
    assert_eq!(String::from_utf8_lossy(&run_output.stdout), "[0, 1, 2]\n");
}

/// Nested constructor patterns: `case Some(Some(v))` reaches into a
/// two-level ADT and binds the inner payload. Pre-Pattern code only
/// supported flat `case Ctor(name)` and could not express nesting.
#[test]
fn match_supports_nested_constructor_patterns() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "enum Option<a> { case Some(v: a); case None }\n\
             val nested = Some(Some(7))\n\
             val flat = Some(None)\n\
             def describe(o) = o match {\n  \
               case Some(Some(v)) => toString(v)\n  \
               case Some(None) => \"some-none\"\n  \
               case None => \"none\"\n\
             }\n\
             println(describe(nested))\n\
             println(describe(flat))\n\
             println(describe(None))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        "7\nsome-none\nnone\n()\n"
    );
}

/// Literal integer patterns: arms can match an exact integer
/// scrutinee without going through an ADT first.
#[test]
fn match_supports_integer_literal_patterns() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "def label(n) = n match {\n  \
               case 0 => \"zero\"\n  \
               case 1 => \"one\"\n  \
               case _ => \"other\"\n\
             }\n\
             println(label(0))\n\
             println(label(1))\n\
             println(label(42))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        "zero\none\nother\n()\n"
    );
}

/// Variable binding patterns + match guards: a lowercase pattern
/// binds the scrutinee to a name, and `if <expr>` narrows the arm
/// further. The first arm that both matches and satisfies its guard
/// wins.
#[test]
fn match_supports_variable_pattern_with_guard() {
    let output = Command::new(klassic_bin())
        .args([
            "-e",
            "def sign(n) = n match {\n  \
               case 0 => \"zero\"\n  \
               case x if x > 0 => \"pos\"\n  \
               case _ => \"neg\"\n\
             }\n\
             println(sign(5))\n\
             println(sign(0))\n\
             println(sign(-3))",
        ])
        .output()
        .expect("binary should run");

    assert!(
        output.status.success(),
        "exit failure\nstdout:\n{}\nstderr:\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    assert_eq!(
        String::from_utf8_lossy(&output.stdout),
        "pos\nzero\nneg\n()\n"
    );
}

/// String literal patterns: arms can match against exact string
